mapper.update:
UPDATE tnt_library SET
    name               = #{name},
    status             = #{status,typeHandler=org.apache.ibatis.type.EnumTypeHandler},
    address_json       = CAST(#{addressJson} AS jsonb),
    contact_json       = CAST(#{contactJson} AS jsonb),
    opening_hours_json = CAST(#{openingHoursJson} AS jsonb),
    deleted_at         = #{deletedAt},
    updated_by         = #{updatedBy}
WHERE id = #{id}
  AND version = #{version}

mapper.sql:
WHERE deleted_at IS NULL

    AND name ILIKE CONCAT('%', #{name}, '%')


    AND status = #{status}
